files.content:
.custom-modal {
  position: fixed;
  inset: 0;
  z-index: 9999;
}

.custom-modal__backdrop {
  position: absolute;
  inset: 0;
  border: 0;
  background: rgba(0, 0, 0, 0.82);
  backdrop-filter: blur(10px);
  cursor: pointer;
}

.custom-modal__content {
  position: relative;
  z-index: 1;
  display: flex;
  width: 100vw;
  height: 100vh;
  align-items: center;
}

.custom-modal__close {
  position: absolute;
  top: 1.5vw;
  right: 1.5vw;
  z-index: 20;
  display: flex;
  min-width: 42px;
  min-height: 42px;
  width: 3vw;
  height: 3vw;
  align-items: center;
  justify-content: center;
  border: 0;
  border-radius: 999px;
  background: rgba(0, 0, 0, 0.8);
  color: #fff;
  cursor: pointer;
  backdrop-filter: blur(10px);
}

"use client";

import { useEffect } from "react";
import { X } from "lucide-react";
import "./modal.css";

export default function Modal({
  isOpen = false,
  onClose,
  children,
  className = "",
  contentClassName = "",
  showCloseButton = true,
  closeOnBackdrop = true,
  closeOnEsc = true,
  closeButtonClassName = "",
}) {
  useEffect(() => {
    if (!isOpen) return undefined;

    const handleKeyDown = (event) => {
      if (closeOnEsc && event.key === "Escape") onClose?.();
    };

    document.addEventListener("keydown", handleKeyDown);
    document.body.style.overflow = "hidden";

    return () => {
      document.removeEventListener("keydown", handleKeyDown);
      document.body.style.overflow = "";
    };
  }, [closeOnEsc, isOpen, onClose]);

  return (
    <div
      className={`custom-modal ${className} duration-500 ${
        isOpen ? "pointer-events-auto opacity-100" : "pointer-events-none opacity-0"
      }`}
    >
      <button
        type="button"
        className="custom-modal__backdrop"
        aria-label="Close modal"
        onClick={closeOnBackdrop ? onClose : undefined}
      />

      <div className={`custom-modal__content ${contentClassName}`}>
        {showCloseButton ? (
          <button
            type="button"
            className={`custom-modal__close ${closeButtonClassName}`}
            onClick={onClose}
            aria-label="Close modal"
          >
            <X size={24} />
          </button>
        ) : null}
        {children}
      </div>
    </div>
  );
}
